 * This rule throws an exception when it is visited more than once.
 */
private class WithStateRule : Rule(
    ruleId = RuleId("test:with-state"),
    about = About(),
) {
    private var hasNotBeenVisitedYet = true

    override fun beforeFirstNode(editorConfig: EditorConfig) {
        check(hasNotBeenVisitedYet) {
            "Rule has been visited before"
        }
        hasNotBeenVisitedYet = false
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        emit(node.startOffset, "Fake violation which can be autocorrected", true)
    }
}

/**
 * A rule that replaces 'aaa' with 'bbb'. This can be used to test multi-run format together with [ReplaceBbbWithCccRule].
 */
private class ReplaceAaaWithBbbRule : Rule(
    ruleId = RuleId("test:replace-aaa-with-bbb"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text.contains("aaa")) {
            emit(node.startOffset, "Replace aaa with bbb", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText(node.text.replace("aaa", "bbb"))
            }
        }
    }
}

/**
 * A rule that replaces 'bbb' with 'ccc'. This can be used to test multi-run format together with [ReplaceAaaWithBbbRule].
 */
private class ReplaceBbbWithCccRule : Rule(
    ruleId = RuleId("test:replace-bbb-with-ccc"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text.contains("bbb")) {
            emit(node.startOffset, "Replace bbb with ccc", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText(node.text.replace("bbb", "ccc"))
            }
        }
    }
}"}

