            // After first run: "bbb" (from aaa->bbb by Rule 1, and the bbb is detected but not yet autocorrected by Rule 2 since it was changed by Rule 1)
            // After second run: "ccc" (from bbb->ccc by Rule 2)
            val code =
                """
                val foo = "aaa"
                """.trimIndent()
            val formattedCode =
                """
                val foo = "ccc"
                """.trimIndent()
            val actualFormattedCode =
                KtLintRuleEngine(
                    ruleProviders =
                        setOf(
                            RuleProvider { ReplaceAaaWithBbbRule() },
                            RuleProvider { ReplaceBbbWithCccRule() },
                        ),
                ).format(Code.fromSnippet(code))
            assertThat(actualFormattedCode).isEqualTo(formattedCode)
        }

        @Test
        fun `Given code that is already properly formatted then only one format run is needed`() {
            val code =
                """
                val foo = "ccc"
                """.trimIndent()
            val callbacks = mutableListOf<CallbackResult>()
            val actualFormattedCode =
                KtLintRuleEngine(
                    ruleProviders =
                        setOf(
                            RuleProvider { ReplaceAaaWithBbbRule() },
                            RuleProvider { ReplaceBbbWithCccRule() },
                        ),
                ).format(Code.fromSnippet(code)) { e, corrected ->
                    callbacks.add(
                        CallbackResult(
                            line = e.line,
                            col = e.col,
                            ruleId = e.ruleId,
                            detail = e.detail,
                            canBeAutoCorrected = e.canBeAutoCorrected,
                            corrected = corrected,
                        ),
                    )
                }
            assertThat(actualFormattedCode).isEqualTo(code)
            assertThat(callbacks).isEmpty()
        }

        @Test
        fun `Given code with a violation that is autocorrected in the first run then the callback reports the corrected violation`() {
            val code =
                """
                val foo = "bbb"
                """.trimIndent()
            val formattedCode =
                """
                val foo = "ccc"
                """.trimIndent()
            val callbacks = mutableListOf<CallbackResult>()
            val actualFormattedCode =
                KtLintRuleEngine(
                    ruleProviders =
                        setOf(
                            RuleProvider { ReplaceAaaWithBbbRule() },
                            RuleProvider { ReplaceBbbWithCccRule() },
                        ),
                ).format(Code.fromSnippet(code)) { e, corrected ->
                    callbacks.add(
                        CallbackResult(
                            line = e.line,
                            col = e.col,
                            ruleId = e.ruleId,
                            detail = e.detail,
                            canBeAutoCorrected = e.canBeAutoCorrected,
                            corrected = corrected,
                        ),
                    )
                }
            assertThat(actualFormattedCode).isEqualTo(formattedCode)
            // The violation found in the first run should be reported as corrected
            assertThat(callbacks).isEmpty() // No errors in final run because the code was fully formatted
        }
    }

