) : Rule(
    ruleId = RuleId("test:replace-aaa-with-bbb"),
    about = About(),
    visitorModifiers = if (runAsLate) setOf(RunAsLateAsPossible) else emptySet(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text.contains("aaa")) {
            emit(node.startOffset, "Replace aaa with bbb", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText(node.text.replace("aaa", "bbb"))
            }
        }
    }
}

/**
 * A rule that replaces 'bbb' with 'ccc'. When combined with [ReplaceAaaWithBbbRule], this tests the multi-run format
 * feature where one rule creates a condition that another rule should fix.
 */
private class ReplaceBbbWithCccRule : Rule(
    ruleId = RuleId("test:replace-bbb-with-ccc"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text.contains("bbb")) {
            emit(node.startOffset, "Replace bbb with ccc", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText(node.text.replace("bbb", "ccc"))
            }
        }
    }
}"}

