     * Fix style violations in [code] for lint errors when possible. If [code] is passed as file reference then the '.editorconfig' files on
     * the path are taken into account. For each lint violation found, the [callback] is invoked.
     *
     * The format is repeated until the code is fully formatted, or until a maximum of [MAX_FORMAT_RUNS_PER_FILE] format runs is reached.
     * The best results are returned, but it is possible that not all violations can be autocorrected.
     *
     * @throws KtLintParseException if text is not a valid Kotlin code
     * @throws KtLintRuleException in case of internal failure caused by a bug in rule implementation
     */
    public fun format(
        code: Code,
        callback: (LintError, Boolean) -> Unit = { _, _ -> },
    ): String {
        LOGGER.debug { "Starting with formatting file '${code.fileNameOrStdin()}'" }

        val hasUTF8BOM = code.content.startsWith(UTF8_BOM)
        var currentCode = code
        var mutated = false

        // Reformat the code until no more auto-corrections are made, or max runs is reached
        for (formatRunCount in 1..MAX_FORMAT_RUNS_PER_FILE) {
            val formatRunResult = formatOnce(currentCode, formatRunCount)
            if (formatRunResult.mutated) {
                mutated = true
                currentCode = Code.fromSnippetWithPath(formatRunResult.formattedCode, code)
                if (formatRunCount < MAX_FORMAT_RUNS_PER_FILE) {
                    LOGGER.debug {
                        "Format run $formatRunCount of file '${code.fileNameOrStdin()}' completed with ${formatRunResult.correctedErrors.size} " +
                            "autocorrected error(s). Starting format run ${formatRunCount + 1}."
                    }
                }
            } else {
                // No more changes were made, return the formatted code with errors from the final run
                LOGGER.debug { "Format completed after $formatRunCount run(s) for file '${code.fileNameOrStdin()}'" }
                formatRunResult
                    .errors
                    .sortedWith { (l), (r) -> if (l.line != r.line) l.line - r.line else l.col - r.col }
                    .forEach { (e, corrected) -> callback(e, corrected) }
                return if (hasUTF8BOM && mutated) {
                    UTF8_BOM + formatRunResult.formattedCode
                } else if (mutated) {
                    formatRunResult.formattedCode
                } else {
                    code.content
                }.also {
                    LOGGER.debug { "Finished with formatting file '${code.fileNameOrStdin()}'" }
                }
            }
        }

        // Max format runs reached, do a final lint run to get the remaining errors
        LOGGER.warn {
            "Format reached the maximum number of $MAX_FORMAT_RUNS_PER_FILE runs for file '${code.fileNameOrStdin()}'. " +
                "The result is still not fully formatted."
        }

        val finalLintResult = lintAfterFormat(currentCode)
        finalLintResult
            .sortedWith { l, r -> if (l.line != r.line) l.line - r.line else l.col - r.col }
            .forEach { e -> callback(e, false) }

        return if (hasUTF8BOM) {
            UTF8_BOM + currentCode.content.removePrefix(UTF8_BOM)
        } else {
            currentCode.content
        }.also {
            LOGGER.debug { "Finished with formatting file '${code.fileNameOrStdin()}'" }
        }
    }

    private data class FormatRunResult(
        val formattedCode: String,
        val errors: Set<Pair<LintError, Boolean>>,
        val correctedErrors: Set<LintError>,
        val mutated: Boolean,
    )

    /**
     * Run a single format pass on the given [code].
     */
    private fun formatOnce(
        code: Code,
        formatRunCount: Int,
    ): FormatRunResult {
        val ruleExecutionContext = createRuleExecutionContext(this, code)

        var mutated = false
        val errors = mutableSetOf<Pair<LintError, Boolean>>()
        val correctedErrors = mutableSetOf<LintError>()
        val visitorProvider = VisitorProvider(ruleExecutionContext.ruleProviders)
        visitorProvider
            .visitor()
            .invoke { rule ->
                ruleExecutionContext.executeRule(rule, true) { offset, errorMessage, canBeAutoCorrected ->
                    if (canBeAutoCorrected) {
                        mutated = true
                        /**
                         * Rebuild the suppression locator after each change in the AST as the offsets of the
                         * suppression hints might have changed.
                         */
                        ruleExecutionContext.rebuildSuppressionLocator()
                    }
                    val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                    val lintError = LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected)
                    errors.add(
                        Pair(
                            lintError,
                            // It is assumed that a rule that emits that an error can be autocorrected, also
                            // does correct the error.
                            canBeAutoCorrected,
                        ),
                    )
                    if (canBeAutoCorrected) {
                        correctedErrors.add(lintError)
                    }
                    // In trace mode report the violation immediately. The order in which violations are actually found might be different
                    // from the order in which they are reported. For debugging purposes it can be helpful to know the exact order in which
                    // violations are being solved.
                    LOGGER.trace {
                        "Format violation (run $formatRunCount): ${code.fileNameOrStdin()}:$line:$col: $errorMessage (${rule.ruleId})" +
                            canBeAutoCorrected.ifFalse { " [cannot be autocorrected]" }
                    }
                }
            }

        val formattedCode =
            ruleExecutionContext
                .rootNode
                .text
                .replace("\n", ruleExecutionContext.determineLineSeparator(code.content))

        return FormatRunResult(
            formattedCode = formattedCode,
            errors = errors,
            correctedErrors = correctedErrors,
            mutated = mutated,
        )
    }

    /**
     * Run a lint pass on the code after formatting to identify remaining lint violations.
     */
    private fun lintAfterFormat(code: Code): List<LintError> {
        val ruleExecutionContext = createRuleExecutionContext(this, code)
        val errors = mutableListOf<LintError>()
        VisitorProvider(ruleExecutionContext.ruleProviders)
            .visitor()
            .invoke { rule ->
                ruleExecutionContext.executeRule(rule, false) { offset, errorMessage, canBeAutoCorrected ->
                    val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                    errors.add(LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected))
                }
            }
        return errors
    }"}

