                }
            assertThat(actualFormattedCode).isEqualTo(code)
            assertThat(callbacks).isEmpty()
        }

        @Test
        fun `Given code with a violation that is autocorrected then the corrected violation is reported`() {
            val code =
                """
                val foo = "bbb"
                """.trimIndent()
            val formattedCode =
                """
                val foo = "ccc"
                """.trimIndent()
            val callbacks = mutableListOf<CallbackResult>()
            val actualFormattedCode =
                KtLintRuleEngine(
                    ruleProviders =
                        setOf(
                            RuleProvider { ReplaceAaaWithBbbRule() },
                            RuleProvider { ReplaceBbbWithCccRule() },
                        ),
                ).format(Code.fromSnippet(code)) { e, corrected ->
                    callbacks.add(
                        CallbackResult(
                            line = e.line,
                            col = e.col,
                            ruleId = e.ruleId,
                            detail = e.detail,
                            canBeAutoCorrected = e.canBeAutoCorrected,
                            corrected = corrected,
                        ),
                    )
                }
            assertThat(actualFormattedCode).isEqualTo(formattedCode)
            // The autocorrected violation should be reported
            assertThat(callbacks).hasSize(1)
            assertThat(callbacks.first().corrected).isTrue()
        }
    }"}
